#include <stdio.h>
#include <stdlib.h>
#include <limits.h>

long long maxCoins(int N, int B, long long M, long long L, int* S) {
    long long dp[N + 1][B + 1][L + 1];
    for (int i = 0; i <= N; i++) {
        for (int j = 0; j <= B; j++) {
            for (int k = 0; k <= L; k++) {
                dp[i][j][k] = LLONG_MIN;
            }
        }
    }
    dp[0][0][0] = M;
    for (int i = 0; i < N; i++) {
        for (int j = 0; j <= B; j++) {
            for (int k = 0; k <= L; k++) {
                if (dp[i][j][k] != LLONG_MIN) {
                    for (int bet = 0; bet <= L && bet <= k; bet++) {
                        long long win = dp[i][j][k] + (B * bet);
                        long long lose = dp[i][j][k] - bet;
                        dp[i + 1][j + 1][k - bet] = (dp[i + 1][j + 1][k - bet] > win) ? dp[i + 1][j + 1][k - bet] : win;
                        dp[i + 1][j][k - bet] = (dp[i + 1][j][k - bet] > lose) ? dp[i + 1][j][k - bet] : lose;
                    }
                }
            }
        }
    }
    long long max = LLONG_MIN;
    for (int i = 0; i <= B; i++) {
        for (int j = 0; j <= L; j++) {
            max = (max > dp[N][i][j]) ? max : dp[N][i][j];
        }
    }
    return max;
}

int main() {
